import React, { useState, useEffect } from 'react';
import './Slider.css';

const slides = [
  {
    id: 1,
    title: "Gelecek Burada",
    desc: "Yapay zeka odaklı modern arayüz tasarımlarıyla tanışın.",
    img: "https://images.unsplash.com/photo-1614850523296-d8c1af93d400?q=80&w=1200",
  },
  {
    id: 2,
    title: "Yaratıcı Kodlama",
    desc: "Hızlı, güvenli ve kullanıcı dostu deneyimler inşa ediyoruz.",
    img: "https://images.unsplash.com/photo-1620641788421-7a1c342ea42e?q=80&w=1200",
  },
  {
    id: 3,
    title: "Sınırsız Keşif",
    desc: "Veritabanından arayüze kadar her noktada mükemmellik.",
    img: "https://images.unsplash.com/photo-1618005198919-d3d4b5a92ead?q=80&w=1200",
  }
];

const Slider = () => {
  const [current, setCurrent] = useState(0);

  // Otomatik geçiş (opsiyonel)
  useEffect(() => {
    const timer = setInterval(() => {
      setCurrent((prev) => (prev === slides.length - 1 ? 0 : prev + 1));
    }, 5000);
    return () => clearInterval(timer);
  }, []);

  const nextSlide = () => setCurrent(current === slides.length - 1 ? 0 : current + 1);
  const prevSlide = () => setCurrent(current === 0 ? slides.length - 1 : current - 1);

  return (
    <div className="modern-slider">
      {slides.map((slide, index) => (
        <div className={`slide-item ${index === current ? 'active' : ''}`} key={slide.id}>
          <img src={slide.img} alt={slide.title} className="slide-bg" />
          <div className="slide-overlay"></div>
          
          <div className="slide-content">
            <span className="slide-badge">Yeni Nesil</span>
            <h2>{slide.title}</h2>
            <p>{slide.desc}</p>
            <div className="slide-actions">
              <button className="btn-primary">Hemen Başla</button>
              <button className="btn-outline">İncele</button>
            </div>
          </div>
        </div>
      ))}

      {/* Navigasyon Okları */}
      <button className="nav-arrow prev" onClick={prevSlide}>&#10094;</button>
      <button className="nav-arrow next" onClick={nextSlide}>&#10095;</button>

      {/* Sayfalama Noktaları */}
      <div className="dots-container">
        {slides.map((_, index) => (
          <div 
            key={index} 
            className={`dot ${index === current ? 'active' : ''}`}
            onClick={() => setCurrent(index)}
          />
        ))}
      </div>
    </div>
  );
};

export default Slider;
